+/// Drive a task through the cancel protocol after CancelRequested:
+/// CancelRequested → Cancelling → Finalizing → Completed(Cancelled).
+fn drive_cancel_from_requested(
+    oracle: &mut CancellationProtocolOracle,
+    task_id: TaskId,
+    reason: &CancelReason,
+    cleanup_budget: Budget,
+    cancel_t: u64,
+    finalize_t: u64,
+    complete_t: u64,
+) {
+    oracle.on_transition(
+        task_id,
+        &TaskState::CancelRequested {
+            reason: reason.clone(),
+            cleanup_budget,
+        },
+        &TaskState::Cancelling {
+            reason: reason.clone(),
+            cleanup_budget,
+        },
+        t(cancel_t),
+    );
+    oracle.on_transition(
+        task_id,
+        &TaskState::Cancelling {
+            reason: reason.clone(),
+            cleanup_budget,
+        },
+        &TaskState::Finalizing {
+            reason: reason.clone(),
+            cleanup_budget,
+        },
+        t(finalize_t),
+    );
+    oracle.on_transition(
+        task_id,
+        &TaskState::Finalizing {
+            reason: reason.clone(),
+            cleanup_budget,
+        },
+        &TaskState::Completed(Outcome::Cancelled(reason.clone())),
+        t(complete_t),
+    );
+}
